mapper.select:
SELECT a.id indentid, a.order_number orderNumber, a.license_plate carId, a.brand_id brand, a.username name, a.insurance_company insuranceCompany, a.phone_number phone, a.day,day, a.send_unit sendUnit, a.fixloss money, a.fixloss_user fixMoney, date_format(a.creat_time,'%Y-%m') MonthTime, b.merchants_name merchantsName FROM app_indent as a LEFT JOIN app_b_user AS b ON a.user_b_id = b.id WHERE a.user_id = #{id}
AND (a.state = 4 OR a.state = 5)
AND a.state=#{state}
AND year(a.creat_time) = #{year} AND month(a.creat_time) = #{month}
ORDER BY a.creat_time DESC limit #{pagesize},20
